auto
overlap_transform(const int l_a, const int l_c, const double* rterms, const std::size_t cdim, double* spherical) -> void
{
    switch (l_a * 5 + l_c)
    {
        case 0: overlap_transform_0_0(rterms, cdim, spherical); break;
        case 1: overlap_transform_0_1(rterms, cdim, spherical); break;
        case 2: overlap_transform_0_2(rterms, cdim, spherical); break;
        case 3: overlap_transform_0_3(rterms, cdim, spherical); break;
        case 4: overlap_transform_0_4(rterms, cdim, spherical); break;
        case 5: overlap_transform_1_0(rterms, cdim, spherical); break;
        case 6: overlap_transform_1_1(rterms, cdim, spherical); break;
        case 7: overlap_transform_1_2(rterms, cdim, spherical); break;
        case 8: overlap_transform_1_3(rterms, cdim, spherical); break;
        case 9: overlap_transform_1_4(rterms, cdim, spherical); break;
        case 10: overlap_transform_2_0(rterms, cdim, spherical); break;
        case 11: overlap_transform_2_1(rterms, cdim, spherical); break;
        case 12: overlap_transform_2_2(rterms, cdim, spherical); break;
        case 13: overlap_transform_2_3(rterms, cdim, spherical); break;
        case 14: overlap_transform_2_4(rterms, cdim, spherical); break;
        case 15: overlap_transform_3_0(rterms, cdim, spherical); break;
        case 16: overlap_transform_3_1(rterms, cdim, spherical); break;
        case 17: overlap_transform_3_2(rterms, cdim, spherical); break;
        case 18: overlap_transform_3_3(rterms, cdim, spherical); break;
        case 19: overlap_transform_3_4(rterms, cdim, spherical); break;
        case 20: overlap_transform_4_0(rterms, cdim, spherical); break;
        case 21: overlap_transform_4_1(rterms, cdim, spherical); break;
        case 22: overlap_transform_4_2(rterms, cdim, spherical); break;
        case 23: overlap_transform_4_3(rterms, cdim, spherical); break;
        case 24: overlap_transform_4_4(rterms, cdim, spherical); break;
        default: break;
    }
}

